function sizeToBytes(input) {
  if (input == null) return NaN;

  const s = String(input).trim();
  if (!s) return NaN;

  // Fast path: pure number => bytes
  if (/^\d+(\.\d+)?$/.test(s)) return Math.round(Number(s));

  // Normalize: remove commas, collapse spaces
  const normalized = s.replace(/,/g, "").replace(/\s+/g, " ").trim();

  // e.g. "2.2MB", "2.2 MB", "456 bytes", "10B", "1.5GiB"
  const match = normalized.match(/^(\d+(?:\.\d+)?)\s*(bytes?|b|kib|kb|mib|mb|gib|gb|tib|tb)$/i);
  if (!match) return NaN;

  const value = Number(match[1]);
  const unitRaw = match[2].toLowerCase();

  // Decimal (SI): KB=1000, MB=1000^2, ...
  const DEC = { b: 1, kb: 1e3, mb: 1e6, gb: 1e9, tb: 1e12 };
  // Binary (IEC): KiB=1024, MiB=1024^2, ...
  const BIN = { kib: 1024, mib: 1024 ** 2, gib: 1024 ** 3, tib: 1024 ** 4 };

  let multiplier;
  if (unitRaw === "byte" || unitRaw === "bytes" || unitRaw === "b") multiplier = 1;
  else if (unitRaw in DEC) multiplier = DEC[unitRaw];
  else if (unitRaw in BIN) multiplier = BIN[unitRaw];
  else return NaN;

  return Math.round(value * multiplier);
}

return {size:sizeToBytes($('Download vimeo').first().binary.data.fileSize)}
